#
# TABLE STRUCTURE FOR: alert_category_tbl
#

DROP TABLE IF EXISTS `alert_category_tbl`;

CREATE TABLE `alert_category_tbl` (
  `alert_cat_id` tinyint(5) NOT NULL AUTO_INCREMENT,
  `alert_category` varchar(256) COLLATE utf8_sinhala_ci NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`alert_cat_id`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8 COLLATE=utf8_sinhala_ci;



#
# TABLE STRUCTURE FOR: alert_tbl
#

DROP TABLE IF EXISTS `alert_tbl`;

CREATE TABLE `alert_tbl` (
  `alert_id` tinyint(4) NOT NULL AUTO_INCREMENT,
  `alert_cat_id` tinyint(4) NOT NULL,
  `alert_desc` varchar(256) COLLATE utf8_sinhala_ci NOT NULL,
  `by_whom` varchar(256) COLLATE utf8_sinhala_ci NOT NULL,
  `to_whom` varchar(256) COLLATE utf8_sinhala_ci NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  `is_read` tinyint(1) NOT NULL DEFAULT '0',
  `when_read` datetime NOT NULL,
  PRIMARY KEY (`alert_id`),
  KEY `alert_cat_id` (`alert_cat_id`),
  CONSTRAINT `alert_tbl_ibfk_1` FOREIGN KEY (`alert_cat_id`) REFERENCES `alert_category_tbl` (`alert_cat_id`)
) ENGINE=InnoDB AUTO_INCREMENT=87 DEFAULT CHARSET=utf8 COLLATE=utf8_sinhala_ci;



