  `subject_id` int(5) NOT NULL AUTO_INCREMENT,
  `subject` varchar(255) CHARACTER SET utf8 NOT NULL,
  `section_id` int(2) NOT NULL,
  `sub_cat_id` int(2) NOT NULL,
  PRIMARY KEY (`subject_id`)
) ENGINE=InnoDB AUTO_INCREMENT=119 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: subjects_grade_tbl
#

DROP TABLE IF EXISTS `subjects_grade_tbl`;

CREATE TABLE `subjects_grade_tbl` (
  `subj_grd_id` int(11) NOT NULL AUTO_INCREMENT,
  `census_id` varchar(5) NOT NULL,
  `grade_id` int(2) NOT NULL,
  `subject_id` int(5) NOT NULL,
  `year` year(4) NOT NULL,
  `order_id` int(2) NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  PRIMARY KEY (`subj_grd_id`)
) ENGINE=InnoDB AUTO_INCREMENT=585 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: teacher_increment_inform_tbl
#

DROP TABLE IF EXISTS `teacher_increment_inform_tbl`;

CREATE TABLE `teacher_increment_inform_tbl` (
  `tr_inc_inform_id` int(11) NOT NULL AUTO_INCREMENT,
  `stf_id` int(11) NOT NULL,
  `increment_year` int(4) NOT NULL,
  `sms_sent` tinyint(1) NOT NULL,
  `remarks` varchar(255) NOT NULL,
  `sms_sent_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`tr_inc_inform_id`)
) ENGINE=InnoDB AUTO_INCREMENT=239 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: teacher_increment_status_tbl
#

DROP TABLE IF EXISTS `teacher_increment_status_tbl`;

CREATE TABLE `teacher_increment_status_tbl` (
  `inc_status_id` int(2) NOT NULL AUTO_INCREMENT,
  `inc_status` varchar(255) CHARACTER SET utf8 NOT NULL,
  PRIMARY KEY (`inc_status_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: teacher_increment_tbl
#

DROP TABLE IF EXISTS `teacher_increment_tbl`;

CREATE TABLE `teacher_increment_tbl` (
  `tr_inc_id` int(11) NOT NULL AUTO_INCREMENT,
  `stf_id` int(11) NOT NULL,
  `increment_year` int(4) NOT NULL,
  `inc_status_id` int(2) NOT NULL,
  `defects` tinyint(4) NOT NULL DEFAULT '0',
  `remarks` varchar(255) CHARACTER SET utf8 NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`tr_inc_id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: term_test_absentees_tbl
#

DROP TABLE IF EXISTS `term_test_absentees_tbl`;

CREATE TABLE `term_test_absentees_tbl` (
  `absent_id` int(11) NOT NULL AUTO_INCREMENT,
  `index_no` varchar(5) NOT NULL,
  `year` int(4) NOT NULL,
  `term` int(1) NOT NULL,
  `subj_id` int(2) NOT NULL,
  `census_id` varchar(5) NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  PRIMARY KEY (`absent_id`)
) ENGINE=InnoDB AUTO_INCREMENT=55 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: term_test_marks_confirm_tbl
#

DROP TABLE IF EXISTS `term_test_marks_confirm_tbl`;

CREATE TABLE `term_test_marks_confirm_tbl` (
  `marks_conf_id` int(11) NOT NULL AUTO_INCREMENT,
  `census_id` varchar(5) NOT NULL,
  `grade_id` int(2) NOT NULL,
  `class_id` int(2) NOT NULL,
  `year` int(4) NOT NULL,
  `term` int(1) NOT NULL,
  `is_completed` tinyint(1) NOT NULL DEFAULT '0',
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  PRIMARY KEY (`marks_conf_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: term_test_marks_tbl
#

DROP TABLE IF EXISTS `term_test_marks_tbl`;

CREATE TABLE `term_test_marks_tbl` (
  `st_mrk_id` int(11) NOT NULL AUTO_INCREMENT,
  `index_no` varchar(5) NOT NULL,
  `year` int(4) NOT NULL,
  `term` int(1) NOT NULL,
  `subj_id` int(2) NOT NULL,
  `marks` int(3) NOT NULL,
  `census_id` varchar(5) NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  PRIMARY KEY (`st_mrk_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1979 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: term_test_results_tbl
#

DROP TABLE IF EXISTS `term_test_results_tbl`;

CREATE TABLE `term_test_results_tbl` (
  `result_id` int(11) NOT NULL AUTO_INCREMENT,
  `census_id` varchar(5) NOT NULL,
  `index_no` varchar(5) NOT NULL,
  `year` int(4) NOT NULL,
  `term` int(1) NOT NULL,
  `total` int(5) NOT NULL,
  `average` decimal(5,2) NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  PRIMARY KEY (`result_id`)
) ENGINE=InnoDB AUTO_INCREMENT=157 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: user_act_type_tbl
#

DROP TABLE IF EXISTS `user_act_type_tbl`;

CREATE TABLE `user_act_type_tbl` (
  `act_type_id` int(2) NOT NULL AUTO_INCREMENT,
  `act_type` varchar(30) COLLATE utf8_sinhala_ci NOT NULL,
  PRIMARY KEY (`act_type_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8 COLLATE=utf8_sinhala_ci;



#
# TABLE STRUCTURE FOR: user_role_tbl
#

DROP TABLE IF EXISTS `user_role_tbl`;

CREATE TABLE `user_role_tbl` (
  `role_id` int(2) NOT NULL AUTO_INCREMENT,
  `roll_name` varchar(30) NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  `is_deleted` tinyint(4) NOT NULL DEFAULT '0',
  PRIMARY KEY (`role_id`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: user_status_tbl
#

DROP TABLE IF EXISTS `user_status_tbl`;

CREATE TABLE `user_status_tbl` (
  `status_id` int(3) NOT NULL AUTO_INCREMENT,
  `status_type` varchar(20) NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  `date_created` date NOT NULL,
  PRIMARY KEY (`status_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: user_tbl
#

DROP TABLE IF EXISTS `user_tbl`;

CREATE TABLE `user_tbl` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT,
  `role_id` int(2) NOT NULL,
  `username` varchar(30) NOT NULL,
  `password` varchar(40) NOT NULL,
  `div_id` varchar(3) NOT NULL,
  `status_id` int(2) NOT NULL DEFAULT '2',
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=124 DEFAULT CHARSET=latin1;



#
# TABLE STRUCTURE FOR: user_track_tbl
#

DROP TABLE IF EXISTS `user_track_tbl`;

CREATE TABLE `user_track_tbl` (
  `user_track_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `key_on_row` varchar(10) COLLATE utf8_sinhala_ci NOT NULL,
  `tbl_name` varchar(60) COLLATE utf8_sinhala_ci NOT NULL,
  `act_type_id` int(2) NOT NULL,
  `note` varchar(255) COLLATE utf8_sinhala_ci NOT NULL,
  `date_added` datetime NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`user_track_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1440 DEFAULT CHARSET=utf8 COLLATE=utf8_sinhala_ci;



#
# TABLE STRUCTURE FOR: year_plan_tbl
#

DROP TABLE IF EXISTS `year_plan_tbl`;

CREATE TABLE `year_plan_tbl` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(60) NOT NULL,
  `description` text NOT NULL,
  `start_event` date NOT NULL,
  `end_event` date NOT NULL,
  `date_added` datetime NOT NULL,
  `date_updated` datetime NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8;



